// ----------------------------------------------------------
// Write buffer
// ----------------------------------------------------------
// Data-phase write qualifier
always @(posedge hclk or negedge hreset_n)
  if (~hreset_n) wr_data_phase <= 1'b0;
  else           wr_data_phase <= ahb_wr;

always @(posedge hclk) begin
  if (wr_byte_en_buf[3] & wr_data_phase) wr_data_buf[31:24] <= hwdata[31:24];
  if (wr_byte_en_buf[2] & wr_data_phase) wr_data_buf[23:16] <= hwdata[23:16];
  if (wr_byte_en_buf[1] & wr_data_phase) wr_data_buf[15: 8] <= hwdata[15: 8];
  if (wr_byte_en_buf[0] & wr_data_phase) wr_data_buf[ 7: 0] <= hwdata[ 7: 0];
end

// Byte enables captured in address phase
always @(posedge hclk or negedge hreset_n)
  if (~hreset_n)     wr_byte_en_buf <= 4'b0000;
  else if (ahb_wr)   wr_byte_en_buf <= wr_byte_en_nxt;

// Address captured in address phase
always @(posedge hclk or negedge hreset_n)
  if (~hreset_n)      wr_addr_buf <= {(g_AW-2){1'b0}};
  else if (ahb_wr)    wr_addr_buf <= haddr[(g_AW-1):2];

// ----------------------------------------------------------
// RAW hazard detection and merge
// ----------------------------------------------------------
wire wr_addr_hit_nxt = (haddr[g_AW-1:2] == wr_addr_buf[g_AW-3:0]) & ahb_rd_raw;
wire wr_addr_hit_eff = wr_addr_hit | wr_addr_hit_nxt;

// Merge read data with buffered write bytes only while a write is actually
// in-flight (data phase now or held as pending due to read overlap).
// Without this gate, a stale last-write value can incorrectly shadow later
// reads to the same address.
wire raw_merge_en = wr_data_phase | wr_pending;
wire [3:0] merge_mask = {4{wr_addr_hit_eff & raw_merge_en}} & wr_byte_en_buf;

wire [31:0] rd_data_merge =
            { merge_mask[3] ? wr_data_buf[31:24] : sramrdata[31:24],
              merge_mask[2] ? wr_data_buf[23:16] : sramrdata[23:16],
              merge_mask[1] ? wr_data_buf[15: 8] : sramrdata[15: 8],
              merge_mask[0] ? wr_data_buf[ 7: 0] : sramrdata[ 7: 0] };

assign hrdata = rd_data_merge;

// ----------------------------------------------------------
// Synchronous state update
// ----------------------------------------------------------
always @(posedge hclk or negedge hreset_n)
  if (~hreset_n) wr_addr_hit <= 1'b0;
  else           wr_addr_hit <= wr_addr_hit_nxt;

always @(posedge hclk or negedge hreset_n)
  if (~hreset_n) wr_pending <= 1'b0;
  else           wr_pending <= wr_pending_nxt;

// Sync read wait insertion (1 cycle)
always @(posedge hclk or negedge hreset_n)
  if (~hreset_n) begin
    rd_wait     <= 1'b0;
    rd_addr_lat <= {(g_AW-2){1'b0}};
  end else begin
    if (rd_wait)
      rd_wait <= 1'b0;
    else if (ahb_rd)
      rd_wait <= 1'b1;
    else
      rd_wait <= 1'b0;

    if (ahb_rd)
      rd_addr_lat <= haddr[(g_AW-1):2];
  end

// SRAM write data comes from pending buffer if present
assign sramwdata = (wr_pending) ? wr_data_buf : hwdata[31:0];

// ----------------------------------------------------------
// Outputs
// ----------------------------------------------------------
// Backpressure all read address phases (including write/read overlap).
